args.sparql:
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>

SELECT ?battle ?battleLabel ?date
WHERE {
  ?battle wdt:P31/wdt:P279 wd:Q178561 ;
          wdt:P710 wd:Q3624335 ;
          wdt:P1260 wd:Q1569377 ;
          wdt:P585 ?date .
  ?battle rdfs:label ?battleLabel .
  FILTER (lang(?battleLabel) = 'en')
  FILTER (SUBSTR(STR(?date), 2, 4) >= '1156' && SUBSTR(STR(?date), 2, 4) <= '1500')
}
LIMIT 10
